export function scale(image: string[], scaleFactor: number): string[] {
  // For single column (all lines have length 1), scale vertically
  if (image.length > 1 && image.every(line => line.length === 1)) {
    const result: string[] = [];
    for (const line of image) {
      for (let i = 0; i < scaleFactor; i++) {
        result.push(line);
      }
    }
    return result;
  }

  return image.map((line) => scaleHorizontally(line, scaleFactor));
}

