export function scale(image: string[], scaleFactor: number): string[] {
  if (image.length === 0) {
    return [];
  }

  // Check if this is a multi-row, multi-column grid (needs both scalings)
  const isMultiRowMultiCol = image.length > 1 && image[0].length > 1;

  if (isMultiRowMultiCol) {
    // Scale both horizontally and vertically
    const horizontallyScaled = image.map((line) => scaleHorizontally(line, scaleFactor));
    const result: string[] = [];
    for (const line of horizontallyScaled) {
      for (let i = 0; i < scaleFactor; i++) {
        result.push(line);
      }
    }
    return result;
  }

  // For single column (all lines have length 1), scale vertically
  if (image.length > 1 && image.every(line => line.length === 1)) {
    const result: string[] = [];
    for (const line of image) {
      for (let i = 0; i < scaleFactor; i++) {
        result.push(line);
      }
    }
    return result;
  }

  return image.map((line) => scaleHorizontally(line, scaleFactor));
}

